    /// Config file path
    #[arg(long, short, global = true, value_hint = ValueHint::FilePath)]
    pub config: Option<PathBuf>,

    /// Log level
    #[arg(long, global = true, add = ArgValueCompleter::new(complete_log_levels))]
    pub log_level: Option<String>,

    #[command(subcommand)]
